function globalCuisineRecipe(id, title, cuisine, category, description, ingredients, steps, tags = [], extras = {}) {
  return expansionRecipe(
    id,
    title,
    category,
    extras.image || cuisineCoverImages[cuisine] || "assets/editorial-cooking-hero.jpg",
    extras.prep || "20 min",
    extras.cook || "30 min",
    extras.servings || 4,
    extras.level || "Beginner",
    description,
    ingredients,
    steps,
    [...tags, "global cuisine", cuisine],
    {
      cuisine,
      path: extras.path || "amateur-cooks",
      kidsKorner: extras.kidsKorner,
      ageTrack: extras.ageTrack,
      helperNote: extras.helperNote,
      storage: extras.storage || "Refrigerate leftovers in a covered container for up to 3 days.",
      reheating: extras.reheating || "Reheat gently until hot throughout."
    }
  );
}

