function recipeCard(recipe) {
  const isPersonal = personalRecipeIds.includes(recipe.id);
  const resolvedPhoto = resolveRecipeImage(recipe);
  return `
    <article class="recipe-card">
      <a class="recipe-photo ${resolvedPhoto.source === "queued-for-replacement" ? "photo-needed-frame" : ""}" href="#recipes/${recipe.id}"><img src="${resolvedPhoto.image}" alt="${recipe.title}" />${recipePhotoStatusBadge(resolvedPhoto)}</a>
      <div class="recipe-content">
        <div class="recipe-card-topline">
          ${recipe.isUserRecipe ? `<span>My Kitchen</span>` : isPersonal ? `<span>Shay's Kitchen</span>` : `<span>${cuisineName(recipe.cuisine)}</span>`}
          <span>${recipe.skill_level}</span>
        </div>
        <div class="recipe-story-label">${recipeStoryLabel(recipe)}</div>
        <h3>${recipe.title}</h3>
        ${recipe.review_status === "pending" ? `<p class="pending-review-note">Pending review. Saved to your recipe collection.</p>` : ""}
        <div class="recipe-mini-meta">
          <span>${recipeDuration(recipe)}</span>
          <span>${recipe.difficulty}</span>
          <span>${recipe.servings} servings</span>
        </div>
        <p>${recipe.description}</p>
        <div class="ingredient-preview"><strong>Ingredients:</strong> ${recipe.ingredients.slice(0, 4).join(", ")}</div>
        <div class="card-actions"><a class="small-button" href="#recipes/${recipe.id}">View Recipe</a><button class="small-button secondary" data-save="${recipe.id}">${saved.includes(recipe.id) ? "Saved" : "&#9825; Save"}</button><button class="small-button secondary road-trip-cooked-button ${cookedRecipes.includes(recipe.id) ? "cooked" : ""}" data-cooked="${recipe.id}">${cookedRecipes.includes(recipe.id) ? "Cooked" : "Cooked It"}</button>${recipe.video_url ? `<a class="small-button secondary" href="${recipe.video_url}" target="_blank" rel="noreferrer">&#9654; Watch</a>` : ""}</div>
      </div>
    </article>
  `;
}

function personalRecipes() {
  const shayRecipes = personalRecipeIds.map((id) => recipeById(id)).filter(Boolean);
  return [...userRecipeCollection(), ...shayRecipes];
}

function compactRecipe(recipe) {
  if (!recipe) return "";
  return `<div class="compact-recipe"><img src="${recipePhotoFor(recipe)}" alt="${recipe.title}" /><div><strong>${recipe.title}</strong><span>${recipe.time} / ${recipe.level}</span></div><button class="small-button secondary" data-plan="${recipe.id}">${planned.includes(recipe.id) ? "Remove" : "Plan"}</button></div>`;
}

function userRecipeCollection() {
  return (userRecipes || []).map((recipe) => normalizeRecipe({ ...recipe, isUserRecipe: true }));
}

function splitRecipeLines(value = "") {
  return String(value)
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);
}

function userRecipeFallbackImage(cuisine, category) {
  const canonical = canonicalCuisineId(cuisine || "");
  return cuisineCoverImages[canonical]
    || categoryCoverImages[category]
    || photoFor("hero", "family", 0, "assets/cooking-family.jpeg");
}

function readFileAsDataURL(file) {
  return new Promise((resolve) => {
    if (!file?.name) return resolve("");
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result?.toString() || "");
    reader.onerror = () => resolve("");
    reader.readAsDataURL(file);
  });
}

function applyRecipeDatabase(database) {
  if (!database?.recipes?.length) return;
  const bundledRecipes = recipes.map((recipe) => ({ ...recipe }));
  categories = database.categories || categories;
  if (!categories.includes("Party Cups")) categories = [...categories, "Party Cups"];
  personalRecipeIds = database.collections?.shaysKitchen || personalRecipeIds;
  const loadedRecipes = database.recipes.map((recipe) => ({
    id: recipe.id,
    title: recipe.title,
    slug: recipe.slug,
    cuisine: recipe.cuisine,
    category: recipe.category,
    image: recipe.image || recipe.image_url || "assets/logo.png",
    image_url: recipe.image_url || recipe.image || "assets/logo.png",
    time: recipe.cookTime || `${recipe.cookTimeMinutes || 0} min`,
    cookTime: recipe.cookTime || recipe.cook_time,
    cook_time: recipe.cook_time || recipe.cookTime,
    cookTimeMinutes: recipe.cookTimeMinutes,
    skill_level: recipe.skill_level || recipe.skillLevel,
    prepTime: recipe.prepTime || recipe.prep_time,
    prep_time: recipe.prep_time || recipe.prepTime,
    prepTimeMinutes: recipe.prepTimeMinutes,
    level: recipe.difficulty,
    difficulty: recipe.difficulty,
    servings: recipe.servings,
    path: recipe.path || "amateur-home-chef",
    description: recipe.description,
    ingredients: recipe.ingredients || [],
    structured_ingredients: recipe.structured_ingredients || recipe.ingredients_structured || [],
    ingredients_structured: recipe.ingredients_structured || recipe.structured_ingredients || [],
    steps: recipe.instructions || recipe.directions || [],
    directions: recipe.directions || recipe.instructions || [],
    instructions: recipe.instructions || recipe.directions || [],
    tags: recipe.tags || [],
    cultural_variations: recipe.cultural_variations || [],
    video_url: recipe.video_url || recipe.videoUrl || "",
    videoUrl: recipe.videoUrl || recipe.video_url || "",
    related_recipe_ids: recipe.related_recipe_ids || recipe.relatedRecipeIds || [],
    featured: Boolean(recipe.featured),
    chefNotes: recipe.chefNotes || "",
    equipment: recipe.equipment || [],
    tips: recipe.tips || [],
    makeAhead: recipe.makeAhead || "",
    servingIdeas: recipe.servingIdeas || [],
    source: recipe.source || { type: "internal" },
    partyCup: Boolean(recipe.partyCup),
    cost_per_cup: recipe.cost_per_cup || recipe.costPerCup || 0,
    cost_per_guest: recipe.cost_per_guest || recipe.costPerGuest || 0,
    cups_per_guest: recipe.cups_per_guest || recipe.cupsPerGuest || 1,
    shopping_items: recipe.shopping_items || recipe.shoppingItems || []
  }));
  const loadedIds = new Set(loadedRecipes.map((recipe) => recipe.id));
  const missingBundled = bundledRecipes.filter((recipe) => !loadedIds.has(recipe.id));
  recipes = [...loadedRecipes, ...missingBundled].map(normalizeRecipe);
}

async function loadRecipeDatabase() {
  try {
    const response = await fetch("data/recipes.json", { cache: "no-store" });
    if (!response.ok) throw new Error(`Recipe database failed: ${response.status}`);
    applyRecipeDatabase(await response.json());
  } catch (error) {
    console.warn("Using bundled recipe fallback.", error);
  }
}

function submissionCard(submission) {
  return `<article class="submission-card"><strong>${escapeHTML(submission.title)}</strong><span>${escapeHTML(submission.recipeTitle)} / ${escapeHTML(submission.type)}</span></article>`;
}

function learningSearchResults(query) {
  if (!query) return "";
  const normalized = query.toLowerCase();
  const results = [
    ...academyModules
      .filter((module) => [module.title, module.category, module.overview, ...module.keyConcepts].join(" ").toLowerCase().includes(normalized))
      .slice(0, 3)
      .map((module) => ({ type: "Lesson", title: module.title, text: module.overview, href: `#culinary-academy/${module.id}` })),
    ...foodEncyclopedia
      .filter((entry) => [entry.term, entry.origin, entry.purpose, ...(entry.related || [])].join(" ").toLowerCase().includes(normalized))
      .slice(0, 3)
      .map((entry) => ({ type: "Food Term", title: entry.term, text: entry.purpose, href: `#culinary-academy/${slugify(entry.term)}` })),
    ...cuisineExplorerGroups
      .filter((group) => [group.title, group.note, ...group.regions].join(" ").toLowerCase().includes(normalized))
      .slice(0, 2)
      .map((group) => ({ type: "Cuisine", title: group.title, text: group.note, href: `#cuisine-explorer/${group.id}` })),
    ...menuPairings
      .filter((menu) => [menu.cuisine, menu.occasion, menu.main_dish, menu.cultural_notes, ...menu.traditional_sides].join(" ").toLowerCase().includes(normalized))
      .slice(0, 2)
      .map((menu) => ({ type: "Menu Guide", title: menu.main_dish, text: `${menu.cuisine} / ${menu.occasion}`, href: `#what-yall-cooking/${menuPairings.indexOf(menu)}` })),
    ...hostingIdeas
      .filter((idea) => [idea.title, idea.text, ...(idea.setup || [])].join(" ").toLowerCase().includes(normalized))
      .slice(0, 2)
      .map((idea) => ({ type: "Hosting", title: idea.title, text: idea.text, href: `#hosting/${slugify(idea.title)}` }))
  ];
  if (!results.length) return "";
  return `
    <div class="academy-search-results">
      <h3>Learning results</h3>
      <div class="academy-result-grid">
        ${results.map((item) => `<a href="${item.href}"><span>${item.type}</span><strong>${item.title}</strong><p>${item.text}</p></a>`).join("")}
      </div>
    </div>
  `;
}

function handleSearch(event) {
  if (event?.target?.closest("[data-rainbow-checklist]")) {
    const checklist = event.target.closest("[data-rainbow-checklist]");
    const count = checklist.querySelectorAll("input:checked").length;
    const result = document.querySelector("[data-rainbow-result]");
    if (result) result.textContent = count >= 4 ? "Rainbow complete! You found four colors." : `${count} of 4 colors found.`;
    return;
  }
  if (event?.target?.closest("[data-dinner-checklist]")) {
    const checklist = event.target.closest("[data-dinner-checklist]");
    const count = checklist.querySelectorAll("input:checked").length;
    const result = document.querySelector("[data-dinner-result]");
    if (result) result.textContent = count === 5 ? "Dinner helper challenge complete!" : `${count} of 5 jobs complete.`;
    return;
  }
  if (event?.target?.id === "pantryPhotoInput") {
    const file = event.target.files?.[0];
    const preview = document.querySelector("#pantryPhotoPreview");
    if (!file || !preview) return;
    const reader = new FileReader();
    reader.onload = () => {
      preview.innerHTML = `<img src="${reader.result}" alt="Pantry photo preview" /><p>Photo ready. Confirm the visible ingredients beside it.</p>`;
    };
    reader.readAsDataURL(file);
    return;
  }
  if (event?.target?.id === "pantryScanNotes") {
    updatePantryScanResults();
    return;
  }
  renderPartyPlannerResults();
  renderRecipePartyResults();
  const query = document.querySelector("#searchBox")?.value.toLowerCase().trim() || "";
  const pantry = document.querySelector("#pantryBox")?.value.toLowerCase().split(",").map((item) => item.trim()).filter(Boolean) || [];
  const category = document.querySelector("#categoryFilter")?.value || "";
  const cuisine = document.querySelector("#cuisineFilter")?.value || "";
  const maxTime = Number(document.querySelector("#timeFilter")?.value || 0);
  const level = document.querySelector("#levelFilter")?.value || "";
  const quick = document.querySelector(".quick-filter.active")?.dataset.quickFilter || "";
  const results = allRecipeCollection().filter((recipe) => {
    const ingredientText = recipe.ingredients.join(" ").toLowerCase();
    const tagText = (recipe.tags || []).join(" ").toLowerCase();
    const haystack = `${recipe.title} ${recipe.category} ${recipe.level} ${recipe.difficulty || ""} ${recipe.description} ${ingredientText} ${tagText}`.toLowerCase();
    const hasPantryItems = !pantry.length || pantry.every((item) => ingredientText.includes(item));
    const quickMatch = !quick
      || (quick.startsWith("cuisine:") && recipe.cuisine === quick.replace("cuisine:", ""))
      || (quick.startsWith("category:") && (recipe.category === quick.replace("category:", "") || recipe.tags?.includes(quick.replace("category:", ""))))
      || (quick.startsWith("skill:") && recipe.skill_level === quick.replace("skill:", ""));
    return quickMatch
      && (!query || haystack.includes(query))
      && hasPantryItems
      && (!category || recipe.category === category || recipe.tags?.includes(category))
      && (!cuisine || recipe.cuisine === cuisine)
      && (!maxTime || (recipe.cookTimeMinutes || 999) <= maxTime)
      && (!level || recipe.level === level || recipe.difficulty === level);
  });
  const resultsNode = document.querySelector("#results");
  if (resultsNode) {
    resultsNode.innerHTML = results.length ? results.map(recipeCard).join("") : `<div class="empty-state">No recipes found yet.</div>`;
  }
  const learningNode = document.querySelector("#learningResults");
  if (learningNode) learningNode.innerHTML = learningSearchResults(query || pantry[0] || "");
}

function handleClick(event) {
  const kidsAnswer = event.target.closest("[data-kids-answer]");
  const rainbowChecklist = event.target.closest("[data-rainbow-checklist]");
  const dinnerChecklist = event.target.closest("[data-dinner-checklist]");
  const quickFilter = event.target.closest("[data-quick-filter]");
  const saveButton = event.target.closest("[data-save]");
  const cookedButton = event.target.closest("[data-cooked]");
  const planButton = event.target.closest("[data-plan]");
  const printButton = event.target.closest("[data-print-recipe]");
  const pantryChip = event.target.closest("[data-pantry-chip]");
  const pantryModeButton = event.target.closest("[data-pantry-mode]");
  const pantryRunButton = event.target.closest("[data-run-pantry-scan]");
  const pantryFavoriteButton = event.target.closest("[data-save-pantry-favorites]");
  const pantryClearButton = event.target.closest("[data-clear-pantry-scan]");
  const juneteenthMenuButton = event.target.closest("[data-juneteenth-menu]");
  const regionalMenuButton = event.target.closest("[data-regional-menu]");
  const recipeSetButton = event.target.closest("[data-use-recipe-set]");
  const saveCurrentMenuButton = event.target.closest("[data-save-current-menu]");
  const useSavedMenuButton = event.target.closest("[data-use-saved-menu]");
  const clearPlannedButton = event.target.closest("[data-clear-planned]");
  if (kidsAnswer) {
    const result = kidsAnswer.closest(".kids-game-card")?.querySelector("[data-kids-game-result]");
    const correct = kidsAnswer.dataset.kidsAnswer === "true";
    if (result) result.textContent = correct ? "You got it! Berries add color and fruit." : "Try again. Pick the ingredient that is safe and fruity.";
    kidsAnswer.closest(".kids-choice-list")?.querySelectorAll("button").forEach((button) => button.classList.toggle("selected", button === kidsAnswer));
    return;
  }
  if (rainbowChecklist) {
    requestAnimationFrame(() => {
      const count = rainbowChecklist.querySelectorAll("input:checked").length;
      const result = document.querySelector("[data-rainbow-result]");
      if (result) result.textContent = count >= 4 ? "Rainbow complete! You found four colors." : `${count} of 4 colors found.`;
    });
    return;
  }
  if (dinnerChecklist) {
    requestAnimationFrame(() => {
      const count = dinnerChecklist.querySelectorAll("input:checked").length;
      const result = document.querySelector("[data-dinner-result]");
      if (result) result.textContent = count === 5 ? "Dinner helper challenge complete!" : `${count} of 5 jobs complete.`;
    });
    return;
  }
  if (pantryChip) {
    pantryChip.classList.toggle("active");
    updatePantryScanResults();
    return;
  }
  if (pantryModeButton) {
    document.querySelectorAll("[data-pantry-mode]").forEach((button) => button.classList.toggle("active", button === pantryModeButton));
    pantryScanState = { ...pantryScanState, mode: pantryModeButton.dataset.pantryMode };
    localStorage.setItem("letsCookPantryScan", JSON.stringify(pantryScanState));
    updatePantryScanResults();
    return;
  }
  if (pantryRunButton) {
    updatePantryScanResults();
    return;
  }
  if (pantryFavoriteButton) {
    pantryFavoriteIngredients = pantryIngredientsFromDom();
    localStorage.setItem("letsCookPantryFavorites", JSON.stringify(pantryFavoriteIngredients));
    renderPantryScan();
    return;
  }
  if (pantryClearButton) {
    pantryScanState = { ingredients: [], notes: "", mode: pantryModeFromState() };
    localStorage.removeItem("letsCookPantryScan");
    renderPantryScan();
    return;
  }
  if (clearPlannedButton) {
    planned = [];
    persistLetsCookState();
    render();
    return;
  }
  if (recipeSetButton) {
    const ids = recipeSetButton.dataset.useRecipeSet.split(",").map((id) => id.trim()).filter((id) => recipeById(id));
    planned = [...new Set([...planned, ...ids])];
    persistLetsCookState();
    render();
    return;
  }
  if (saveCurrentMenuButton) {
    const index = Number(saveCurrentMenuButton.dataset.saveCurrentMenu || 0);
    const menu = menuPairings[Math.max(0, Math.min(menuPairings.length - 1, index))] || menuPairings[0];
    const menuRecipes = recipesForMenu(menu);
    const savedMenu = {
      id: `menu-${Date.now()}`,
      title: `${menu.cuisine} ${menu.occasion}`,
      audience: "Menu Planner",
      recipeIds: menuRecipes.map((recipe) => recipe.id),
      createdAt: new Date().toISOString()
    };
    savedMenus = [savedMenu, ...savedMenus].slice(0, 12);
    persistLetsCookState();
    render();
    return;
  }
  if (useSavedMenuButton) {
    const menu = savedMenus.find((item) => item.id === useSavedMenuButton.dataset.useSavedMenu);
    if (menu) {
      planned = [...new Set([...planned, ...(menu.recipeIds || []).filter((id) => recipeById(id))])];
      persistLetsCookState();
      render();
    }
    return;
  }
  if (regionalMenuButton) {
    const section = regionalMenuButton.closest("[data-regional-menu-section]");
    const output = section?.querySelector("[data-regional-output]");
    const isNewEnglandRegion = Boolean(newEnglandRegionalPages[regionalMenuButton.dataset.regionId]);
    const page = regionalSoulFoodPages[regionalMenuButton.dataset.regionId]
      || midwestRegionalPages[regionalMenuButton.dataset.regionId]
      || newEnglandRegionalPages[regionalMenuButton.dataset.regionId]
      || southwestRegionalPages[regionalMenuButton.dataset.regionId]
      || midAtlanticRegionalPages[regionalMenuButton.dataset.regionId]
      || westernRegionalPages[regionalMenuButton.dataset.regionId]
      || regionalSoulFoodPages["mississippi-soul-food"];
    const menu = page.menus.find((item) => item.id === regionalMenuButton.dataset.regionalMenu) || page.menus[0];
    section?.querySelectorAll("[data-regional-menu]").forEach((button) => button.classList.toggle("secondary", button !== regionalMenuButton));
    if (output) output.innerHTML = regionalMenuOutput(page, menu, { allowQueued: isNewEnglandRegion });
    return;
  }
  if (juneteenthMenuButton) {
    const section = juneteenthMenuButton.closest("[data-juneteenth-menu-section]");
    const output = section?.querySelector("[data-juneteenth-output]");
    const menu = monthlySpotlight.menus.find((item) => item.id === juneteenthMenuButton.dataset.juneteenthMenu) || monthlySpotlight.menus[0];
    section?.querySelectorAll("[data-juneteenth-menu]").forEach((button) => button.classList.toggle("secondary", button !== juneteenthMenuButton));
    if (output) output.innerHTML = juneteenthMenuOutput(menu);
    return;
  }
  if (quickFilter) {
    document.querySelectorAll(".quick-filter").forEach((button) => button.classList.toggle("active", button === quickFilter && !button.classList.contains("active")));
    handleSearch();
    return;
  }
  if (saveButton) {
    saved = toggleValue(saved, saveButton.dataset.save);
    persistLetsCookState();
    render();
  }
  if (cookedButton) {
    cookedRecipes = toggleValue(cookedRecipes, cookedButton.dataset.cooked);
    syncRoadTripPassport(cookedButton.dataset.cooked);
    persistLetsCookState();
    render();
  }
  if (planButton) {
    planned = toggleValue(planned, planButton.dataset.plan);
    persistLetsCookState();
    render();
  }
  if (printButton) {
    window.print();
  }
}


async function handleSubmit(event) {
  if (event.target.matches("[data-kids-safety-quiz]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const score = [
      formData.get("oven") === "Ask a grown-up",
      formData.get("spill") === "Wipe it up",
      formData.get("hands") === "Wash hands with soap"
    ].filter(Boolean).length;
    const result = event.target.querySelector("[data-kids-safety-result]");
    if (result) result.textContent = score === 3 ? "3 out of 3! Kitchen Safety badge work complete." : `${score} out of 3. Review the safety lesson and try again.`;
    return;
  }
  if (event.target.matches("[data-kids-create-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const base = formData.get("base")?.toString() || "";
    const protein = formData.get("protein")?.toString() || "";
    const color = formData.get("color")?.toString() || "";
    const crunch = formData.get("crunch")?.toString() || "";
    const output = document.querySelector("[data-kids-create-output]");
    if (output) {
      output.innerHTML = `
        <span>🎉</span>
        <h2>Your snack: The Color Crunch Plate</h2>
        <p>Arrange <strong>${base}</strong> with <strong>${protein}</strong>, <strong>${color}</strong>, and <strong>${crunch}</strong>. Ask a grown-up to check allergies and help with any cutting.</p>
      `;
    }
    return;
  }

  if (event.target.matches("[data-encyclopedia-form], [data-academy-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const term = formData.get("term")?.toString().trim() || "";
    window.location.hash = term ? `#culinary-academy/${encodeURIComponent(term)}` : "#culinary-academy";
    return;
  }

  if (event.target.matches("[data-ingredient-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const ingredient = formData.get("ingredient")?.toString().trim() || "chicken strips";
    window.location.hash = `#kitchen-search/${encodeURIComponent(ingredient)}`;
    return;
  }

  if (event.target.matches("[data-menu-builder-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const selected = Number(formData.get("main"));
    window.location.hash = `#what-yall-cooking/${Number.isFinite(selected) ? selected : 0}`;
    return;
  }

  if (event.target.matches("[data-menu-planner-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const selected = Number(formData.get("main"));
    const servings = Number(formData.get("servings"));
    const audience = formData.get("audience")?.toString() || "single";
    window.location.hash = `#planner/${Number.isFinite(selected) ? selected : 0}-${plannerServingOptions.includes(servings) ? servings : 6}-${audience}`;
    return;
  }

  if (event.target.matches("[data-add-recipe-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const title = formData.get("title")?.toString().trim() || "Untitled Recipe";
    const cuisine = formData.get("cuisine")?.toString() || "global";
    const category = formData.get("category")?.toString() || "Family Dinners";
    const photo = formData.get("photo");
    const uploadedPhoto = await readFileAsDataURL(photo);
    const idBase = `user-${slugify(title) || "recipe"}`;
    const id = userRecipes.some((recipe) => recipe.id === idBase) ? `${idBase}-${Date.now()}` : idBase;
    const newRecipe = normalizeRecipe({
      id,
      slug: id.replace(/^user-/, ""),
      title,
      cuisine,
      category,
      image: uploadedPhoto || userRecipeFallbackImage(cuisine, category),
      image_url: uploadedPhoto || userRecipeFallbackImage(cuisine, category),
      prep_time: formData.get("prepTime")?.toString().trim() || "15 min",
      cook_time: formData.get("cookTime")?.toString().trim() || "30 min",
      difficulty: formData.get("difficulty")?.toString() || "Beginner",
      servings: Number(formData.get("servings")) || 4,
      description: formData.get("notes")?.toString().trim() || `${title} submitted from My Kitchen.`,
      ingredients: splitRecipeLines(formData.get("ingredients")?.toString() || ""),
      directions: splitRecipeLines(formData.get("instructions")?.toString() || ""),
      instructions: splitRecipeLines(formData.get("instructions")?.toString() || ""),
      tags: [category, cuisine, "user recipe", "pending review"],
      skill_level: "Home Cook",
      review_status: "pending",
      isUserRecipe: true,
      created_at: new Date().toISOString(),
      source: { type: "user-submitted", name: "My Kitchen" }
    });
    userRecipes = [newRecipe, ...userRecipes].slice(0, 50);
    saved = [...new Set([newRecipe.id, ...saved])];
    localStorage.setItem("letsCookUserRecipes", JSON.stringify(userRecipes));
    persistLetsCookState();
    window.location.hash = `#recipes/${newRecipe.id}`;
    return;
  }

  if (event.target.matches("[data-lets-signup-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    await submitLetsCookAuth("/api/lets-cook/signup", {
      displayName: formData.get("displayName")?.toString().trim(),
      email: formData.get("email")?.toString().trim(),
      password: formData.get("password")?.toString()
    });
    return;
  }

  if (event.target.matches("[data-lets-login-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    await submitLetsCookAuth("/api/lets-cook/login", {
      email: formData.get("email")?.toString().trim(),
      password: formData.get("password")?.toString()
    });
    return;
  }

  if (event.target.matches("[data-lets-logout-form]")) {
    event.preventDefault();
    const response = await fetch("/api/lets-cook/logout", { method: "POST" });
    const payload = response.ok ? await response.json() : {};
    applyLetsCookState(payload, "You are logged out.");
    renderAccount();
    return;
  }

  if (event.target.matches("[data-lets-profile-form]")) {
    event.preventDefault();
    const formData = new FormData(event.target);
    const photo = formData.get("photo");
    if (photo?.name) {
      const photoData = new FormData();
      photoData.append("photo", photo);
      const photoResponse = await fetch("/api/lets-cook/profile-photo", { method: "POST", body: photoData });
      const photoPayload = await photoResponse.json().catch(() => ({}));
      if (!photoResponse.ok) {
        letsCookSession = { ...letsCookSession, status: photoPayload.error || "Profile picture upload failed." };
        renderAccount();
        return;
      }
      applyLetsCookState(photoPayload, "Profile picture saved.");
    }
    const profileResponse = await fetch("/api/lets-cook/profile", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        displayName: formData.get("displayName")?.toString().trim(),
        username: formData.get("username")?.toString().trim(),
        bio: formData.get("bio")?.toString().trim(),
        city: formData.get("city")?.toString().trim(),
        state: formData.get("state")?.toString().trim(),
        accountType: formData.get("accountType")?.toString().trim()
      })
    });
    const profilePayload = await profileResponse.json().catch(() => ({}));
    applyLetsCookState(profilePayload, profileResponse.ok ? "Profile saved." : profilePayload.error || "Profile save failed.");
    renderAccount();
    return;
  }


  if (!event.target.matches("[data-upload-form]")) return;
  event.preventDefault();
  const formData = new FormData(event.target);
  const recipe = recipes.find((item) => item.id === formData.get("recipeId"));
  const file = formData.get("file");
  const url = formData.get("url")?.toString().trim() || "";
  formData.set("recipeTitle", recipe?.title || "Recipe");
  if (letsCookSession.authenticated) {
    const response = await fetch("/api/lets-cook/food-videos", {
      method: "POST",
      body: formData
    });
    const payload = await response.json().catch(() => ({}));
    if (!response.ok) {
      letsCookSession = { ...letsCookSession, status: payload.error || "Food video upload failed." };
      renderAccount();
      return;
    }
    applyLetsCookState(payload, "Food video saved.");
    render();
    return;
  }
  submissions = [{
    id: Date.now().toString(),
    recipeTitle: recipe?.title || "Recipe",
    title: formData.get("title")?.toString().trim() || "Cook video",
    type: url ? "YouTube link" : file?.name ? `Local file: ${file.name}` : "Draft upload"
  }, ...submissions];
  localStorage.setItem("letsCookSubmissions", JSON.stringify(submissions));
  render();
}

function toggleValue(list, value) {
  return list.includes(value) ? list.filter((item) => item !== value) : [...list, value];
}

async function loadLetsCookState() {
  try {
    const response = await fetch("/api/lets-cook/state", { cache: "no-store" });
    if (!response.ok) throw new Error(`Let's Cook state failed: ${response.status}`);
    const payload = await response.json();
    applyLetsCookState(payload);
  } catch (error) {
    console.warn("Using browser-only Let's Cook state fallback.", error);
  }
}

function applyLetsCookState(payload, status = "") {
  if (!payload) return;
  letsCookSession = {
    authenticated: Boolean(payload.authenticated),
    user: payload.user || null,
    status
  };
  saved = payload.saved || saved || [];
  cookedRecipes = payload.cookedRecipes || cookedRecipes || [];
  planned = payload.planned || planned || [];
  recentlyViewed = payload.recentlyViewed || recentlyViewed || [];
  savedMenus = payload.savedMenus || savedMenus || [];
  lessonProgress = payload.lessonProgress || lessonProgress || {};
  submissions = payload.submissions || submissions || [];
  if (Array.isArray(payload.userRecipes) && (payload.authenticated || payload.userRecipes.length)) {
    userRecipes = payload.userRecipes;
  }
}

async function submitLetsCookAuth(url, payload) {
  const response = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload)
  });
  const data = await response.json().catch(() => ({}));
  applyLetsCookState(data, response.ok ? "Your Let's Cook account is connected." : data.error || "Account request failed.");
  renderAccount();
}

async function persistLetsCookState() {
  localStorage.setItem("letsCookSaved", JSON.stringify(saved));
  localStorage.setItem("letsCookCookedRecipes", JSON.stringify(cookedRecipes));
  localStorage.setItem("letsCookPlanned", JSON.stringify(planned));
  localStorage.setItem("letsCookRecentlyViewed", JSON.stringify(recentlyViewed));
  localStorage.setItem("letsCookSavedMenus", JSON.stringify(savedMenus));
  localStorage.setItem("letsCookUserRecipes", JSON.stringify(userRecipes));
  localStorage.setItem("letsCookLessonProgress", JSON.stringify(lessonProgress));
  localStorage.setItem("letsCookRoadTripPassport", JSON.stringify(roadTripPassport));
  if (!letsCookSession.authenticated) {
    return false;
  }
  const response = await fetch("/api/lets-cook/state", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ saved, cookedRecipes, planned, recentlyViewed, savedMenus, lessonProgress, userRecipes })
  });
  const payload = await response.json().catch(() => ({}));
  applyLetsCookState(payload, response.ok ? "Saved to your Let's Cook account." : payload.error || "Save failed.");
  return response.ok;
}

function readJSON(key, fallback) {
  try {
    return JSON.parse(localStorage.getItem(key) || JSON.stringify(fallback));
  } catch {
    return fallback;
  }
}

function escapeHTML(value) {
  return String(value ?? "").replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;").replaceAll('"', "&quot;").replaceAll("'", "&#039;");
}

function userInitials(user = {}) {
  const name = user.displayName || user.fullName || user.email || "SB";
  return name.replace("/", " ").split(/\s+/).filter(Boolean).slice(0, 2).map((part) => part[0]).join("").toUpperCase() || "SB";
}

function accountAvatar(user = {}, className = "profile-avatar") {
  const src = user.avatarUrl || user.profilePic || "";
  return src
    ? `<img class="${className}" src="${escapeHTML(src)}" alt="${escapeHTML(user.displayName || "Profile picture")}" />`
    : `<div class="${className} initials-avatar" aria-label="${escapeHTML(user.displayName || "Profile")}">${escapeHTML(user.initials || userInitials(user))}</div>`;
}

Promise.all([loadRecipeDatabase(), loadLetsCookState()]).finally(() => {
  render();
  announceRouteChange();
  scrollToRouteTop("auto");
});
